// .vscode/settings.json — project-level Claude Code configuration
{
  // Share VS Code diagnostics (errors/warnings from linters) with Claude automatically
  "claudeCode.includeProblems": true,

  // Files to exclude from Claude's file tree context
  "claudeCode.excludePatterns": [
    "**/node_modules/**",
    "**/.git/**",
    "**/dist/**",
    "**/build/**",
    "**/.env*"           // Never include environment files with secrets
  ],

  // Maximum tokens to send as file context per request
  "claudeCode.maxContextTokens": 50000,

  // Show Claude's file edits as VS Code diff views (recommended)
  "claudeCode.showDiffView": true
}

// keybindings.json — customize keyboard shortcuts
// (File -> Preferences -> Keyboard Shortcuts -> Open keybindings.json icon)
[
  {
    "key": "ctrl+shift+c",          // Open Claude Code panel
    "command": "claude-code.openPanel"
  },
  {
    "key": "ctrl+shift+l",          // Send selection to Claude
    "command": "claude-code.sendSelection",
    "when": "editorHasSelection"
  },
  {
    "key": "ctrl+shift+a",          // Accept current Claude diff
    "command": "claude-code.acceptDiff"
  }
]

// JetBrains IDE integration
// Supports IntelliJ IDEA, PyCharm, WebStorm, GoLand (version 2023.2+)

// Installation via IDE:
// Settings -> Plugins -> Marketplace -> Search "Claude Code" -> Install

// Or via plugin XML manifest (for automation):
// Plugins directory: ~/.config/JetBrains/<IDE>/plugins/
// Or install from .zip: Help -> Find Action -> "Install Plugin from Disk"

// The JetBrains plugin reads the same ~/.claude/settings.json as the terminal
// so your project CLAUDE.md, permissions, and model settings apply in the IDE

// Default keyboard shortcuts (customize in Settings -> Keymap -> Claude Code):
// Ctrl+Shift+C  — Open Claude Code tool window
// Ctrl+Enter    — Send current selection to Claude (from any editor)
// Alt+Shift+A   — Accept all Claude's pending changes

// JetBrains-specific features:
// - Integration with built-in VCS diff viewer for reviewing Claude's file changes
// - Access to IDE inspection results (code analysis, type errors) as context
// - Compatible with JetBrains Fleet remote development environments

-- Neovim integration using avante.nvim
-- File: ~/.config/nvim/lua/plugins/avante.lua

return {
  "yetone/avante.nvim",
  event = "VeryLazy",
  version = false,
  opts = {
    provider = "claude",
    claude = {
      endpoint = "https://api.anthropic.com",
      model = "claude-opus-4-5",
      timeout = 30000,
      temperature = 0,
      max_tokens = 8096,
      -- API key comes from ANTHROPIC_API_KEY env var (never hardcode)
    },
    behaviour = {
      auto_suggestions = false,
      auto_apply_diff_after_generation = false,
    },
    -- Key mappings
    mappings = {
      ask = "<leader>aa",   -- Open Claude chat panel
      edit = "<leader>ae",  -- Edit selected code with Claude
      refresh = "<leader>ar",
      diff = {
        ours = "co",        -- Keep our version in conflict
        theirs = "ct",      -- Take their version in conflict
        all_theirs = "ca",
        both = "cb",
      },
    },
  },
  dependencies = {
    "stevearc/dressing.nvim",
    "nvim-lua/plenary.nvim",
    "MunifTanjim/nui.nvim",
  },
}

-- Alternative: use Claude Code CLI directly in a terminal split
-- :split | :terminal claude  (runs CLI in a split terminal pane)
